const VB_W = 900, VB_H = 747.4;
const NS = "http://www.w3.org/2000/svg";

function initMap(opts) {
    const svg = document.getElementById(opts.svgId);
    const mapWrap = document.getElementById(opts.wrapId);
    const tagEl = document.getElementById(opts.tagId);
    if (!svg || !mapWrap || !tagEl) return; // 해당 지도가 이 페이지에 없으면 조용히 건너뜀

    svg.setAttribute('viewBox', `0 0 ${VB_W} ${VB_H}`);

    REGIONS.forEach(r => {
        const g = document.createElementNS(NS,'g');
        g.setAttribute('class','region');
        g.setAttribute('data-idx', r.idx);

        // 단색 채우기 (질감 없이)
        const fillPoly = document.createElementNS(NS,'polygon');
        fillPoly.setAttribute('points', r.outline);
        fillPoly.setAttribute('class','district-fill');
        fillPoly.style.fill = r.fill;
        g.appendChild(fillPoly);

        // 구역 경계선 (흰색)
        const border = document.createElementNS(NS,'polygon');
        border.setAttribute('points', r.outline);
        border.setAttribute('class','district-border');
        g.appendChild(border);

        // 호버 하이라이트 오버레이
        const overlay = document.createElementNS(NS,'polygon');
        overlay.setAttribute('points', r.outline);
        overlay.setAttribute('class','overlay-poly');
        g.appendChild(overlay);

        g.addEventListener('mouseenter', () => activate(r, g, mapWrap, tagEl));
        g.addEventListener('mouseleave', () => deactivate(g, tagEl));
        g.addEventListener('click', () => {
            if (g.classList.contains('hover')) { deactivate(g, tagEl); }
            else { activate(r, g, mapWrap, tagEl); }
        });

        svg.appendChild(g);
    });

    function activate(r, g, wrap, tag) {
        svg.querySelectorAll('.region.hover').forEach(el => {
            if (el !== g) deactivate(el, tag);
        });
        g.classList.add('hover');

        const s = wrap.getBoundingClientRect().width / VB_W;
        tag.textContent = r.name;
        tag.style.left = (r.cx * s) + 'px';
        tag.style.top = (r.cy * s - 10) + 'px';
        tag.classList.add('show');
    }

    function deactivate(g, tag) {
        g.classList.remove('hover');
        tag.classList.remove('show');
    }
}

// 페이지에 있는 지도 인스턴스마다 호출 (해당 요소가 없으면 initMap이 알아서 건너뜀)
initMap({ svgId: 'overlaySvg',  wrapId: 'mapWrap',        tagId: 'tag' });
initMap({ svgId: 'featureSvg', wrapId: 'mapWrapFeature', tagId: 'tagFeature' });